export function initSwiper() {
    let all_swiper_3 = document.querySelectorAll('.swiper--3');
    let all_swiper_3_end = document.querySelectorAll('.swiper--3-end');
    let all_swiper_4 = document.querySelectorAll('.swiper--4');

    if(all_swiper_3){
        all_swiper_3.forEach(function(swiper_3){
            const swiper_for_3 = new Swiper(swiper_3, {
            // Optional parameters
                slidesPerView: 3,
                spaceBetween: 20,
                allowTouchMove: true,
                breakpoints: {
                    320: {
                        slidesPerView: 1,
                        spaceBetween: 0,
                        allowTouchMove: false,
                    },
                    768.98: {
                        slidesPerView: 2,
                        spaceBetween: 16,
                        allowTouchMove: true,
                    },
                    1300.98: {
                        slidesPerView: 3,
                        spaceBetween: 20,
                        allowTouchMove: true,
                    }
                }
            });
        })
    }

    if(all_swiper_3_end){
        all_swiper_3_end.forEach(function(swiper_3_end){
            const swiper_for_3_end = new Swiper(swiper_3_end, {
            // Optional parameters
                slidesPerView: 'auto',
                spaceBetween: 0,
                allowTouchMove: false,
                breakpoints: {
                    320: {
                        slidesPerView: 'auto',
                        spaceBetween: 10,
                        allowTouchMove: true,
                    },
                    768.98: {
                        slidesPerView: 'auto',
                        spaceBetween: 0,
                        allowTouchMove: false,
                    },
                }
            });
        })
    }

    if(all_swiper_4){
        all_swiper_4.forEach(function(swiper_4){
            const swiper_for_4 = new Swiper(swiper_4, {
            // Optional parameters
                slidesPerView: 4,
                spaceBetween: 20,
                breakpoints: {
                    320: {
                        slidesPerView: 'auto',
                        spaceBetween: 10,
                    },
                    768.98: {
                        slidesPerView: 2,
                        spaceBetween: 16,
                    },
                    1024.98: {
                        slidesPerView: 3,
                        spaceBetween: 16,
                    },
                    1300.98: {
                        slidesPerView: 4,
                        spaceBetween: 20,
                    }
                }
            });
        })
    }

}