export function initFilter() {
    // Dropdown
    let dropdowns = document.querySelectorAll('.dropdown');

    if (dropdowns) {
        document.documentElement.addEventListener('click', function(event){
            if(!event.target.closest('.dropdown')){
                dropdowns.forEach(function(element){
                    element.classList.remove('active');
                    element.parentElement.classList.remove('active');
                })
            }
        })

        dropdowns.forEach(function (dropdown) {
            let dropdown_btn = dropdown.querySelector('.dropdown__btn');
            let dropdown_items = dropdown.querySelectorAll('.dropdown__item');
            let dropdown_input_hidden = dropdown.querySelector('.dropdown__input-hidden');

            if (dropdown_btn) {
                dropdown_btn.addEventListener('click', function (event) {
                    event.preventDefault();

                    if(dropdown.classList.contains('active')){
                        dropdown.classList.remove('active');
                    } else{
                        dropdowns.forEach(function(element){
                            element.classList.remove('active');
                            element.parentElement.classList.remove('active');
                        })

                        dropdown.classList.add('active');
                        dropdown.parentElement.classList.add('active');
                    }
                })

                if (dropdown_items) {
                    dropdown_items.forEach(function (dropdown_item) {
                        dropdown_item.addEventListener('click', function (event) {
                            if (dropdown_btn) {
                                if (dropdown_btn.querySelector('.dropdown__btn-text')) {
                                    dropdown_btn.querySelector('.dropdown__btn-text').textContent = dropdown_item.textContent.trim();
                                } else {
                                    dropdown_btn.textContent = dropdown_item.textContent.trim();
                                }
                            }

                            if (dropdown_input_hidden) {
                                dropdown_input_hidden.value = dropdown_item.dataset.dropdown.trim();
                            }

                            dropdown.classList.remove('active');
                            dropdown.classList.add('selected');
                        })
                    })
                }
            }
        })
    }

    // Filter
    let filter_reset = document.querySelector('.filter__reset');

    if(filter_reset){
        filter_reset.addEventListener('click', function(event){
            event.preventDefault();

            if(dropdowns){
                dropdowns.forEach(function (dropdown) {
                    let dropdown_btn = dropdown.querySelector('.dropdown__btn');
                    let dropdown_input_hidden = dropdown.querySelector('.dropdown__input-hidden');

                    dropdown.classList.remove('selected');

                    if(dropdown_input_hidden){
                        dropdown_input_hidden.value = '';
                    }

                    if(dropdown_btn){
                        let dropdown_btn_text = dropdown_btn.querySelector('.dropdown__btn-text');

                        if(dropdown_btn_text){
                            dropdown_btn_text.textContent = dropdown_btn_text.dataset.text;
                        }
                    }
                })
            }
        })
    }
}